#include <bits/stdc++.h>
#define ll long long
using namespace std;

ll n,tmp,p[15],c[15],cnt;

int main(){
    scanf("%lld",&n);
    tmp=n;
    for(ll i=2;i*i<=tmp;i++)
        if(tmp%i==0){
            ll sum=0;
            while(tmp%i==0)
                tmp/=i,sum++;
            p[cnt]=i,c[cnt]=sum;
            cnt++;
        }
    if(tmp){
        p[cnt]=tmp,c[cnt]=1;
        cnt++;
    }
    ll ans=0;
    for(int i=0;i<1<<cnt;i++){
        ll sum=1,num=n;
        for(int j=0;j<cnt;j++)
            if((i>>j)&1)
                sum*=c[j],num=num*(p[j]-1)/p[j];
        ans+=sum*num;
    }
    printf("%lld",ans);
    return 0;
}
